app.post('/api/calculate', (req, res) => {
    try {
        const b = req.body;
        const age = parseFloat(b.age) || 38;
        const sex = b.sex === "Male" ? "男性_Male" : (b.sex === "Company" ? "法人_CompanyUse" : "女性_Female");
        const sexAgeKey = (b.sex === "Male" ? "M_" : "F_") + age.toFixed(1);

        let f = { b: 1, c: 1, pd: 1, bi: 1 };
        let s = { b: 1, c: 1, pd: 1, bi: 1 };

        function applyValues(c) {
            if (!c) return;
            if (c.modb_f) f.b *= c.modb_f; if (c.modb_s) s.b *= c.modb_s;
            if (c.modc_f) f.c *= c.modc_f; if (c.modc_s) s.c *= c.modc_s;
            if (c.tplpd_f) f.pd *= c.tplpd_f; if (c.tplpd_s) s.pd *= c.tplpd_s;
            if (c.tplbi_f) f.bi *= c.tplbi_f; if (c.tplbi_s) s.bi *= c.tplbi_s;
        }

        function applyDict(factor, val) {
            const dict = DATA[factor] || {};
            applyValues(dict[val] || dict["缺失值"]);
        }

        function applyFunc(factor, val) {
            const list = DATA[factor];
            if (!list || list.length === 0) return;
            for (let i=0; i<list.length; i++) {
                if (val <= list[i].key) { applyValues(JSON.parse(list[i].pStr)); return; }
            }
            applyValues(JSON.parse(list[list.length-1].pStr));
        }

        applyDict("POL_APPLICANT_RMA_RELA", b.applicant_rela || "本人_Myself");
        applyFunc("DRI_insuredAge", age);
        applyDict("DRI_INSURED_SEX_CODE", sex);
        applyDict("DRI_sex_insuredAge", sexAgeKey);
        applyDict("GEO_INSURED_ZIP", String(b.zip_code || "324"));
        applyDict("VEH_MAKE_DESC_group", b.make || "Toyota豐田");
        applyDict("VEH_MOTOR_TYPE", b.motor_type || "自用小客車_PPA");
        applyFunc("VEH_vehAge", parseFloat(b.vehAge) || 1);
        applyFunc("VEH_MOTOR_DISPLACEMENT", parseFloat(b.displacement) || 2000);
        applyDict("VEH_MOTOR_COEFFICIENT", b.motor_coef || "-0.4");
        applyDict("VEH_PASSAGES_PEOPLE", String(b.passages || "4"));
        applyFunc("VEH_RPRICE", parseFloat(b.rPrice) || 2000000);
        applyFunc("VEH_COM_RU1", parseFloat(b.com_ru1) || 5);
        applyFunc("VEH_TFT_RU1", parseFloat(b.tft_ru1) || 7);
        applyDict("POL_SALES_CHANNEL", b.sales_channel || "23.富昇保代");
        applyDict("POL_RESP_RANK", String(b.respRank || "4"));
        applyDict("POL_CY", String(b.pol_cy || "2023"));
        applyDict("POL_renew_flag", b.renew_flag || "N");
        applyDict("POL_SEC_EIP", b.sec_eip || "Y");
        applyDict("POL_TDIR_FLAG", b.tdir_flag || "N");
        applyDict("POL_exLiab_flag", b.exliab_flag || "Y");
        applyDict("CVG_EXCESS_AMT", String(b.excess || "0"));
        applyFunc("CVG_TOTAL_INSURED", parseFloat(b.totalInsured) || 2000000);
        applyFunc("CVG_PER_BODY_AMT", parseFloat(b.per_body_amt) || 2000000);
        applyFunc("CVG_PER_DEATH_AMT", parseFloat(b.per_death_amt) || 3000000);

        const pB = BASE.MODB.f * f.b * BASE.MODB.s * s.b;
        const pC = BASE.MODC.f * f.c * BASE.MODC.s * s.c;
        const pPD = BASE.TPLPD.f * f.pd * BASE.TPLPD.s * s.pd;
        const pBI = BASE.TPLBI.f * f.bi * BASE.TPLBI.s * s.bi * BASE.TPLBI.loading;

        res.status(200).json({
            success: true,
            modB_premium: Math.round(pB),
            modC_premium: Math.round(pC),
            tplPd_premium: Math.round(pPD),
            tplBi_premium: Math.round(pBI)
        });
    } catch (e) { res.status(500).json({ error: e.message }); }
});

app.listen(3000, () => console.log("✅ 最終版 API 已啟動，準備好接軌 Copilot Studio！"));
